INSERT INTO reviews (id, place_id, user_id, rating, content, tags, child_age_months, created_at) VALUES
  ('ac000000-0000-0000-0000-000000000001', 'place_성남_restaurant_001', 'd0000000-0000-0000-0000-000000000003', 5, '선생님이 아이들을 정말 사랑하시는 게 느껴져요. 프로그램도 다양하고 좋아요!', ARRAY['친절해요','야간진료','깨끗해요'], 20, now() + interval '105 days'),
